1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it("returns 105 G for a single sword (100 base + 5 fee)", () => {
14	      const result = processScenario({
15	        customer: { yearsWithMHPCO: 0 },
16	        steps: [
17	          {
18	            op: "quote" as const,
19	            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	          },
21	        ],
22	      });
23	      expect(result.results[0]).toEqual({ premium: 105 });
24	    });
25	    it("returns 65 G for a single amulet (60 base + 5 fee)", () => {
26	      const result = processScenario({
27	        customer: { yearsWithMHPCO: 0 },
28	        steps: [
29	          {
30	            op: "quote" as const,
31	            items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	          },
33	        ],
34	      });
35	      expect(result.results[0]).toEqual({ premium: 65 });
36	    });
37	    it("returns 85 G for a single staff (80 base + 5 fee)", () => {
38	      const result = processScenario({
39	        customer: { yearsWithMHPCO: 0 },
40	        steps: [
41	          {
42	            op: "quote" as const,
43	            items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
44	          },
45	        ],
46	      });
47	      expect(result.results[0]).toEqual({ premium: 85 });
48	    });
49	    it.todo("returns 45 G for a single potion (40 base + 5 fee)");
50	    it.todo("returns 165 G for a sword and an amulet (100 + 60 + 5 fee)");
51	  });
52	
53	  describe("Quote - component premiums", () => {
54	    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
55	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
56	    it.todo("returns 65 G for 3 alike runes (60 block premium + 5 fee)");
57	    it.todo("returns 105 G for 4 runes (no block: 4 * 25 = 100 + 5 fee)");
58	    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 75 + 5 fee)");
59	    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
60	  });
61	
62	  describe("Quote - cursed surcharge", () => {
63	    it.todo("adds 50% surcharge to a cursed sword (100 + 50 + 5 fee = 155 G)");
64	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
65	  });
66	
67	  describe("Quote - high enchantment surcharge", () => {
68	    it.todo("adds 30% surcharge for enchantment level 5 (100 + 30 + 5 fee = 135 G)");
69	    it.todo("does not add surcharge for enchantment level 4");
70	    it.todo("applies both cursed and high enchantment surcharges to the same item");
71	  });
72	
73	  describe("Quote - loyalty discount", () => {
74	    it.todo("applies 20% loyalty discount for customer with 2 years");
75	    it.todo("does not apply loyalty discount for customer with 1 year");
76	  });
77	
78	  describe("Quote - first insurance surcharge", () => {
79	    it.todo("adds 10% first insurance surcharge on policy base premium");
80	  });
81	
82	  describe("Quote - follow-up contract discount", () => {
83	    it.todo("applies 15% follow-up discount on second quote in scenario");
84	  });
85	
86	  describe("Quote - rounding", () => {
87	    it.todo("rounds premium up in MHPCO's favor (ceiling)");
88	  });
89	
90	  describe("Quote - integration", () => {
91	    it.todo("newcomer with cursed sword: 165 G");
92	    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
93	  });
94	
95	  describe("Quote - errors", () => {
96	    it.todo("throws error for unknown item type");
97	  });
98	
99	  describe("Claim - basic payout", () => {
100	    it.todo("applies 100 G deductible per damaged item");
101	    it.todo("fully reimburses standard item damage minus deductible");
102	  });
103	
104	  describe("Claim - dragon material", () => {
105	    it.todo("fully reimburses damage to dragon material items minus deductible");
106	  });
107	
108	  describe("Claim - high enchantment reimbursement", () => {
109	    it.todo("reimburses 50% of damage for enchantment >= 8, then applies deductible");
110	    it.todo("50% rule wins over dragon material when enchantment >= 8");
111	  });
112	
113	  describe("Claim - cap", () => {
114	    it.todo("caps total payout at twice the insurance sum");
115	    it.todo("tracks remaining cap across multiple claims on same policy");
116	  });
117	
118	  describe("Claim - multiple damages in one event", () => {
119	    it.todo("applies deductible per damaged item in same event");
120	    it.todo("handles two damages of same item type when policy covers two");
121	  });
122	
123	  describe("Claim - payout rounding", () => {
124	    it.todo("rounds payout down in MHPCO's favor (floor)");
125	  });
126	
127	  describe("Claim - errors", () => {
128	    it.todo("rejects damage for item type not in policy");
129	    it.todo("rejects more damages of a type than policy covers");
130	    it.todo("rejects negative damage amount");
131	  });
132	});
