1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	const itemPremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
10	
11	export const processScenario = (scenario: any): any => {
12	  const results = scenario.steps.map((step: any) => {
13	    const premium =
14	      step.items.reduce((sum: number, item: any) => sum + itemPremium(item), 0) +
15	      PROCESSING_FEE;
16	    return { premium };
17	  });
18	  return { results };
19	};
20

